243: // CacheUnaryInterceptor caches the response of a request if the request is cacheable.
244: // TODO: we could clean this up by using generics in 1.18+ to avoid the type switch/duplicate code.
245: func CacheUnaryInterceptor(cache cache.Cacher, logger *zap.Logger) grpc.UnaryServerInterceptor {
246: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
247: 		if cache == nil {
248: 			return handler(ctx, req)
249: 		}
250: 
251: 		switch r := req.(type) {
252: 		case *flipt.EvaluationRequest:
253: 			key, err := legacyEvalCachePrefix.Key(r)
254: 			if err != nil {
255: 				logger.Error("getting cache key", zap.Error(err))
256: 				return handler(ctx, req)
257: 			}
258: 
259: 			cached, ok, err := cache.Get(ctx, key)
260: 			if err != nil {
261: 				// if error, log and without cache
262: 				logger.Error("getting from cache", zap.Error(err))
263: 				return handler(ctx, req)
264: 			}
265: 
266: 			if ok {
267: 				resp := &flipt.EvaluationResponse{}
268: 				if err := proto.Unmarshal(cached, resp); err != nil {
269: 					logger.Error("unmarshalling from cache", zap.Error(err))
270: 					return handler(ctx, req)
271: 				}
272: 
273: 				logger.Debug("evaluate cache hit", zap.Stringer("response", resp))
274: 				return resp, nil
275: 			}
276: 
277: 			logger.Debug("evaluate cache miss")
278: 			resp, err := handler(ctx, req)
279: 			if err != nil {
280: 				return resp, err
281: 			}
282: 
283: 			// marshal response
284: 			data, merr := proto.Marshal(resp.(*flipt.EvaluationResponse))
285: 			if merr != nil {
286: 				logger.Error("marshalling for cache", zap.Error(err))
287: 				return resp, err
288: 			}
289: 
290: 			// set in cache
291: 			if cerr := cache.Set(ctx, key, data); cerr != nil {
292: 				logger.Error("setting in cache", zap.Error(err))
293: 			}
294: 
295: 			return resp, err
296: 
297: 		case *flipt.GetFlagRequest:
298: 			key := flagCacheKey(r.GetNamespaceKey(), r.GetKey())
299: 
300: 			cached, ok, err := cache.Get(ctx, key)
301: 			if err != nil {
302: 				// if error, log and continue without cache
303: 				logger.Error("getting from cache", zap.Error(err))
304: 				return handler(ctx, req)
305: 			}
306: 
307: 			if ok {
308: 				// if cached, return it
309: 				flag := &flipt.Flag{}
310: 				if err := proto.Unmarshal(cached, flag); err != nil {
311: 					logger.Error("unmarshalling from cache", zap.Error(err))
312: 					return handler(ctx, req)
313: 				}
314: 
315: 				logger.Debug("flag cache hit", zap.Stringer("flag", flag))
316: 				return flag, nil
317: 			}
318: 
319: 			logger.Debug("flag cache miss")
320: 			resp, err := handler(ctx, req)
321: 			if err != nil {
322: 				return nil, err
323: 			}
324: 
325: 			// marshal response
326: 			data, merr := proto.Marshal(resp.(*flipt.Flag))
327: 			if merr != nil {
328: 				logger.Error("marshalling for cache", zap.Error(err))
329: 				return resp, err
330: 			}
331: 
332: 			// set in cache
333: 			if cerr := cache.Set(ctx, key, data); cerr != nil {
334: 				logger.Error("setting in cache", zap.Error(err))
335: 			}
336: 
337: 			return resp, err
338: 
339: 		case *flipt.UpdateFlagRequest, *flipt.DeleteFlagRequest:
340: 			// need to do this assertion because the request type is not known in this block
341: 			keyer := r.(flagKeyer)
342: 			// delete from cache
343: 			if err := cache.Delete(ctx, flagCacheKey(keyer.GetNamespaceKey(), keyer.GetKey())); err != nil {
344: 				logger.Error("deleting from cache", zap.Error(err))
345: 			}
346: 		case *flipt.CreateVariantRequest, *flipt.UpdateVariantRequest, *flipt.DeleteVariantRequest:
347: 			// need to do this assertion because the request type is not known in this block
348: 			keyer := r.(variantFlagKeyger)
349: 			// delete from cache
350: 			if err := cache.Delete(ctx, flagCacheKey(keyer.GetNamespaceKey(), keyer.GetFlagKey())); err != nil {
351: 				logger.Error("deleting from cache", zap.Error(err))
352: 			}
353: 		case *evaluation.EvaluationRequest:
354: 			key, err := newEvalCachePrefix.Key(r)
355: 			if err != nil {
356: 				logger.Error("getting cache key", zap.Error(err))
357: 				return handler(ctx, req)
358: 			}
359: 
360: 			cached, ok, err := cache.Get(ctx, key)
361: 			if err != nil {
362: 				// if error, log and without cache
363: 				logger.Error("getting from cache", zap.Error(err))
364: 				return handler(ctx, req)
365: 			}
366: 
367: 			if ok {
368: 				resp := &evaluation.EvaluationResponse{}
369: 				if err := proto.Unmarshal(cached, resp); err != nil {
370: 					logger.Error("unmarshalling from cache", zap.Error(err))
371: 					return handler(ctx, req)
372: 				}
373: 
374: 				logger.Debug("evaluate cache hit", zap.Stringer("response", resp))
375: 				switch r := resp.Response.(type) {
376: 				case *evaluation.EvaluationResponse_VariantResponse:
377: 					return r.VariantResponse, nil
378: 				case *evaluation.EvaluationResponse_BooleanResponse:
379: 					return r.BooleanResponse, nil
380: 				default:
381: 					logger.Error("unexpected eval cache response type", zap.String("type", fmt.Sprintf("%T", resp.Response)))
382: 				}
383: 
384: 				return handler(ctx, req)
385: 			}
386: 
387: 			logger.Debug("evaluate cache miss")
388: 			resp, err := handler(ctx, req)
389: 			if err != nil {
390: 				return resp, err
391: 			}
392: 
393: 			evalResponse := &evaluation.EvaluationResponse{}
394: 			switch r := resp.(type) {
395: 			case *evaluation.VariantEvaluationResponse:
396: 				evalResponse.Type = evaluation.EvaluationResponseType_VARIANT_EVALUATION_RESPONSE_TYPE
397: 				evalResponse.Response = &evaluation.EvaluationResponse_VariantResponse{
398: 					VariantResponse: r,
399: 				}
400: 			case *evaluation.BooleanEvaluationResponse:
401: 				evalResponse.Type = evaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE
402: 				evalResponse.Response = &evaluation.EvaluationResponse_BooleanResponse{
403: 					BooleanResponse: r,
404: 				}
405: 			}
406: 
407: 			// marshal response
408: 			data, merr := proto.Marshal(evalResponse)
409: 			if merr != nil {
410: 				logger.Error("marshalling for cache", zap.Error(err))
411: 				return resp, err
412: 			}
413: 
414: 			// set in cache
415: 			if cerr := cache.Set(ctx, key, data); cerr != nil {
416: 				logger.Error("setting in cache", zap.Error(err))
417: 			}
418: 
419: 			return resp, err
420: 		}
421: 
422: 		return handler(ctx, req)
423: 	}
424: }
