426: // EventPairChecker is the middleware side contract for checking if an event pair exists.
427: type EventPairChecker interface {
428: 	Check(eventPair string) bool
429: }
430: 
431: // AuditUnaryInterceptor sends audit logs to configured sinks upon successful RPC requests for auditable events.
432: func AuditUnaryInterceptor(logger *zap.Logger, eventPairChecker EventPairChecker) grpc.UnaryServerInterceptor {
433: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
434: 		resp, err := handler(ctx, req)
435: 		if err != nil {
436: 			return resp, err
437: 		}
438: 
439: 		actor := authn.ActorFromContext(ctx)
440: 
441: 		var event *audit.Event
442: 
443: 		defer func() {
444: 			if event != nil {
445: 				ts := string(event.Type)
446: 				as := string(event.Action)
447: 				eventPair := fmt.Sprintf("%s:%s", ts, as)
448: 
449: 				exists := eventPairChecker.Check(eventPair)
450: 				if exists {
451: 					span := trace.SpanFromContext(ctx)
452: 					span.AddEvent("event", trace.WithAttributes(event.DecodeToAttributes()...))
453: 				}
454: 			}
455: 		}()
456: 
457: 		// Delete request(s) have to be handled separately because they do not
458: 		// return the concrete type but rather an *empty.Empty response.
459: 		switch r := req.(type) {
460: 		case *flipt.DeleteFlagRequest:
461: 			event = audit.NewEvent(audit.FlagType, audit.Delete, actor, r)
462: 		case *flipt.DeleteVariantRequest:
463: 			event = audit.NewEvent(audit.VariantType, audit.Delete, actor, r)
464: 		case *flipt.DeleteSegmentRequest:
465: 			event = audit.NewEvent(audit.SegmentType, audit.Delete, actor, r)
466: 		case *flipt.DeleteDistributionRequest:
467: 			event = audit.NewEvent(audit.DistributionType, audit.Delete, actor, r)
468: 		case *flipt.DeleteConstraintRequest:
469: 			event = audit.NewEvent(audit.ConstraintType, audit.Delete, actor, r)
470: 		case *flipt.DeleteNamespaceRequest:
471: 			event = audit.NewEvent(audit.NamespaceType, audit.Delete, actor, r)
472: 		case *flipt.OrderRulesRequest:
473: 			event = audit.NewEvent(audit.RuleType, audit.Update, actor, r)
474: 		case *flipt.DeleteRuleRequest:
475: 			event = audit.NewEvent(audit.RuleType, audit.Delete, actor, r)
476: 		case *flipt.OrderRolloutsRequest:
477: 			event = audit.NewEvent(audit.RolloutType, audit.Update, actor, r)
478: 		case *flipt.DeleteRolloutRequest:
479: 			event = audit.NewEvent(audit.RolloutType, audit.Delete, actor, r)
480: 		}
481: 
482: 		// Short circuiting the middleware here since we have a non-nil event from
483: 		// detecting a delete.
484: 		if event != nil {
485: 			return resp, err
486: 		}
487: 
488: 		action := audit.GRPCMethodToAction(info.FullMethod)
489: 
490: 		switch r := resp.(type) {
491: 		case *flipt.Flag:
492: 			if action != "" {
493: 				event = audit.NewEvent(audit.FlagType, action, actor, audit.NewFlag(r))
494: 			}
495: 		case *flipt.Variant:
496: 			if action != "" {
497: 				event = audit.NewEvent(audit.VariantType, action, actor, audit.NewVariant(r))
498: 			}
499: 		case *flipt.Segment:
500: 			if action != "" {
501: 				event = audit.NewEvent(audit.SegmentType, action, actor, audit.NewSegment(r))
502: 			}
503: 		case *flipt.Distribution:
504: 			if action != "" {
505: 				event = audit.NewEvent(audit.DistributionType, action, actor, audit.NewDistribution(r))
506: 			}
507: 		case *flipt.Constraint:
508: 			if action != "" {
509: 				event = audit.NewEvent(audit.ConstraintType, action, actor, audit.NewConstraint(r))
510: 			}
511: 		case *flipt.Namespace:
512: 			if action != "" {
513: 				event = audit.NewEvent(audit.NamespaceType, action, actor, audit.NewNamespace(r))
514: 			}
515: 		case *flipt.Rollout:
516: 			if action != "" {
517: 				event = audit.NewEvent(audit.RolloutType, action, actor, audit.NewRollout(r))
518: 			}
519: 		case *flipt.Rule:
520: 			if action != "" {
521: 				event = audit.NewEvent(audit.RuleType, action, actor, audit.NewRule(r))
522: 			}
523: 		case *fauth.CreateTokenResponse:
524: 			event = audit.NewEvent(audit.TokenType, audit.Create, actor, r.Authentication.Metadata)
525: 		}
526: 
527: 		return resp, err
528: 	}
529: }
