603: 			return handler(ctx, req)
604: 		}
605: 
606: 		if fliptVersionHeader := md.Get(fliptAcceptServerVersionHeaderKey); len(fliptVersionHeader) > 0 {
607: 			version := fliptVersionHeader[0]
608: 			if version != "" {
609: 				cv, err := semver.ParseTolerant(version)
610: 				if err != nil {
611: 					logger.Warn("parsing x-flipt-accept-server-version header", zap.String("version", version), zap.Error(err))
612: 					return handler(ctx, req)
613: 				}
614: 
615: 				logger.Debug("x-flipt-accept-server-version header", zap.String("version", version))
616: 				ctx = WithFliptAcceptServerVersion(ctx, cv)
617: 			}
618: 		}
619: 
620: 		return handler(ctx, req)
621: 	}
622: }
