{"content":"1: package analytics
2: 
3: import (
4: 	"context"
5: 	"encoding/json"
6: 	"errors"
7: 	"time"
8: 
9: 	sdktrace "go.opentelemetry.io/otel/sdk/trace"
10: 	"go.uber.org/zap"
11: )
12: 
13: var errNotTransformable = errors.New("event not transformable into evaluation response")
14: 
15: type AnalyticsStoreMutator interface {
16: 	IncrementFlagEvaluationCounts(ctx context.Context, responses []*EvaluationResponse) error
17: 	Close() error
18: }
19: 
20: type EvaluationResponse struct {
21: 	FlagKey         string    `json:"flagKey,omitempty"`
22: 	FlagType        string    `json:"flagType,omitempty"`
23: 	NamespaceKey    string    `json:"namespaceKey,omitempty"`
24: 	Reason          string    `json:"reason,omitempty"`
25: 	Match           *bool     `json:"match,omitempty"`
26: 	EvaluationValue *string   `json:"evaluationValue,omitempty"`
27: 	Timestamp       time.Time `json:"timestamp,omitempty"`
28: 	EntityId        string    `json:"entityId,omitempty"`
29: }
30: 
31: // AnalyticsSinkSpanExporter implements SpanExporter.
32: type AnalyticsSinkSpanExporter struct {
33: 	logger                *zap.Logger
34: 	analyticsStoreMutator AnalyticsStoreMutator
35: }
36: 
37: // NewAnalyticsSinkSpanExporter is the constructor function for an AnalyticsSpanExporter.
38: func NewAnalyticsSinkSpanExporter(logger *zap.Logger, analyticsStoreMutator AnalyticsStoreMutator) *AnalyticsSinkSpanExporter {
39: 	return &AnalyticsSinkSpanExporter{
40: 		logger:                logger,
41: 		analyticsStoreMutator: analyticsStoreMutator,
42: 	}
43: }
44: 
45: // transformSpanEventToEvaluationResponses is a convenience function to transform a span event into an []*EvaluationResponse.
46: func transformSpanEventToEvaluationResponses(event sdktrace.Event) ([]*EvaluationResponse, error) {
47: 	for _, attr := range event.Attributes {
48: 		if string(attr.Key) == "flipt.evaluation.response" {
49: 			evaluationResponseBytes := []byte(attr.Value.AsString())
50: 			var evaluationResponse []*EvaluationResponse
51: 
52: 			if err := json.Unmarshal(evaluationResponseBytes, &evaluationResponse); err != nil {
53: 				return nil, err
54: 			}
55: 
56: 			return evaluationResponse, nil
57: 		}
58: 	}
59: 
60: 	return nil, errNotTransformable
61: }
62: 
63: // ExportSpans transforms the spans into []*EvaluationResponse which the mutator takes to store into an analytics store.
64: func (a *AnalyticsSinkSpanExporter) ExportSpans(ctx context.Context, spans []sdktrace.ReadOnlySpan) error {
65: 	evaluationResponses := make([]*EvaluationResponse, 0)
66: 
67: 	for _, span := range spans {
68: 		for _, event := range span.Events() {
69: 			evaluationResponsesFromSpan, err := transformSpanEventToEvaluationResponses(event)
70: 			if err != nil && !errors.Is(err, errNotTransformable) {
71: 				a.logger.Error("event not decodable into evaluation response", zap.Error(err))
72: 				continue
73: 			}
74: 
75: 			evaluationResponses = append(evaluationResponses, evaluationResponsesFromSpan...)
76: 		}
77: 	}
78: 
79: 	return a.analyticsStoreMutator.IncrementFlagEvaluationCounts(ctx, evaluationResponses)
80: }
81: 
82: // Shutdown closes resources for an AnalyticsStoreMutator.
83: func (a *AnalyticsSinkSpanExporter) Shutdown(_ context.Context) error {
84: 	return a.analyticsStoreMutator.Close()
85: }
