{"content":"1: package authn
2: 
3: import (
4: 	"context"
5: 	"fmt"
6: 	"strings"
7: 
8: 	"go.flipt.io/flipt/internal/server/audit"
9: 	authmiddlewaregrpc "go.flipt.io/flipt/internal/server/authn/middleware/grpc"
10: 	"go.flipt.io/flipt/internal/storage"
11: 	storageauth "go.flipt.io/flipt/internal/storage/authn"
12: 	"go.flipt.io/flipt/rpc/flipt"
13: 	"go.flipt.io/flipt/rpc/flipt/auth"
14: 	"go.uber.org/zap"
15: 	"google.golang.org/grpc"
16: 	"google.golang.org/grpc/metadata"
17: 	"google.golang.org/protobuf/types/known/emptypb"
18: )
19: 
20: const (
21: 	ipKey  = "x-forwarded-for"
22: 	subKey = "sub"
23: )
24: 
25: var _ auth.AuthenticationServiceServer = &Server{}
26: 
27: func GetActorFromAuthentication(authentication *auth.Authentication, ip string) *audit.Actor {
28: 	switch authentication.Method {
29: 	case auth.Method_METHOD_GITHUB:
30: 		return &audit.Actor{
31: 			Authentication: "github",
32: 			Email:          authentication.Metadata["io.flipt.auth.github.email"],
33: 			Name:           authentication.Metadata["io.flipt.auth.github.name"],
34: 			Picture:        authentication.Metadata["io.flipt.auth.github.picture"],
35: 			IP:             ip,
36: 		}
37: 	case auth.Method_METHOD_OIDC:
38: 		return &audit.Actor{
39: 			Authentication: "oidc",
40: 			Email:          authentication.Metadata["io.flipt.auth.oidc.email"],
41: 			Name:           authentication.Metadata["io.flipt.auth.oidc.name"],
42: 			Picture:        authentication.Metadata["io.flipt.auth.oidc.picture"],
43: 			IP:             ip,
44: 		}
45: 	case auth.Method_METHOD_JWT:
46: 		return &audit.Actor{
47: 			Authentication: "jwt",
48: 			Email:          authentication.Metadata["io.flipt.auth.jwt.email"],
49: 			Name:           authentication.Metadata["io.flipt.auth.jwt.name"],
50: 			Picture:        authentication.Metadata["io.flipt.auth.jwt.picture"],
51: 			IP:             ip,
52: 		}
53: 	default:
54: 		authName := strings.ToLower(strings.TrimPrefix(authentication.Method.String(), "METHOD_"))
55: 		return &audit.Actor{
56: 			Authentication: authName,
57: 			IP:             ip,
58: 		}
59: 	}
60: }
61: 
62: func ActorFromContext(ctx context.Context) *audit.Actor {
63: 	var (
64: 		ipAddress string
65: 	)
66: 
67: 	md, _ := metadata.FromIncomingContext(ctx)
68: 	if len(md[ipKey]) > 0 {
69: 		ipAddress = md[ipKey][0]
70: 	}
71: 
72: 	auth := authmiddlewaregrpc.GetAuthenticationFrom(ctx)
73: 	if auth != nil {
74: 		return GetActorFromAuthentication(auth, ipAddress)
75: 	}
76: 
77: 	return &audit.Actor{
78: 		Authentication: "none",
79: 		IP:             ipAddress,
80: 	}
81: }
82: 
83: // Server is the core AuthenticationServiceServer implementations.
84: //
85: // It is the service which presents all Authentications created in the backing auth store.
86: type Server struct {
87: 	logger *zap.Logger
88: 	store  storageauth.Store
89: 
90: 	enableAuditLogging bool
91: 
92: 	auth.UnimplementedAuthenticationServiceServer
93: }
94: 
95: type Option func(*Server)
96: 
97: // WithAuditLoggingEnabled sets the option for enabling audit logging for the auth server.
98: func WithAuditLoggingEnabled(enabled bool) Option {
99: 	return func(s *Server) {
100: 		s.enableAuditLogging = enabled
101: 	}
102: }
103: 
104: func NewServer(logger *zap.Logger, store storageauth.Store, opts ...Option) *Server {
105: 	s := &Server{
106: 		logger: logger,
107: 		store:  store,
108: 	}
109: 
110: 	for _, opt := range opts {
111: 		opt(s)
112: 	}
113: 
114: 	return s
115: }
116: 
117: // RegisterGRPC registers the server as an Server on the provided grpc server.
118: func (s *Server) RegisterGRPC(server *grpc.Server) {
119: 	auth.RegisterAuthenticationServiceServer(server, s)
120: }
121: 
122: func (s *Server) AllowsNamespaceScopedAuthentication(ctx context.Context) bool {
123: 	return false
124: }
125: 
126: // GetAuthenticationSelf returns the Authentication which was derived from the request context.
127: func (s *Server) GetAuthenticationSelf(ctx context.Context, _ *emptypb.Empty) (*auth.Authentication, error) {
128: 	if auth := authmiddlewaregrpc.GetAuthenticationFrom(ctx); auth != nil {
129: 		s.logger.Debug("GetAuthentication", zap.String("id", auth.Id))
130: 
131: 		return auth, nil
132: 	}
133: 
134: 	return nil, authmiddlewaregrpc.ErrUnauthenticated
135: }
136: 
137: // GetAuthentication returns the Authentication identified by the supplied id.
138: func (s *Server) GetAuthentication(ctx context.Context, r *auth.GetAuthenticationRequest) (*auth.Authentication, error) {
139: 	return s.store.GetAuthenticationByID(ctx, r.Id)
140: }
141: 
142: // ListAuthentications produces a set of authentications for the provided method filter and pagination parameters.
143: func (s *Server) ListAuthentications(ctx context.Context, r *auth.ListAuthenticationsRequest) (*auth.ListAuthenticationsResponse, error) {
144: 	req := &storage.ListRequest[storageauth.ListAuthenticationsPredicate]{
145: 		QueryParams: storage.QueryParams{
146: 			Limit:     uint64(r.Limit),
147: 			PageToken: r.PageToken,
148: 		},
149: 	}
150: 
151: 	if r.Method != auth.Method_METHOD_NONE {
152: 		req.Predicate.Method = &r.Method
153: 	}
154: 
155: 	results, err := s.store.ListAuthentications(ctx, req)
156: 	if err != nil {
157: 		s.logger.Error("listing authentication", zap.Error(err))
158: 
159: 		return nil, fmt.Errorf("listing authentications: %w", err)
160: 	}
161: 
162: 	return &auth.ListAuthenticationsResponse{
163: 		Authentications: results.Results,
164: 		NextPageToken:   results.NextPageToken,
165: 	}, nil
166: }
167: 
168: // DeleteAuthentication deletes the authentication with the supplied ID.
169: func (s *Server) DeleteAuthentication(ctx context.Context, req *auth.DeleteAuthenticationRequest) (*emptypb.Empty, error) {
170: 	s.logger.Debug("DeleteAuthentication", zap.String("id", req.Id))
171: 
172: 	if s.enableAuditLogging {
173: 		actor := ActorFromContext(ctx)
174: 
175: 		a, err := s.GetAuthentication(ctx, &auth.GetAuthenticationRequest{
176: 			Id: req.Id,
177: 		})
178: 		if err != nil {
179: 			s.logger.Error("failed to get authentication for audit events", zap.Error(err))
180: 			return nil, err
181: 		}
182: 		if a.Method == auth.Method_METHOD_TOKEN {
183: 			event := audit.NewEvent(audit.TokenType, audit.Delete, actor, a.Metadata)
184: 			event.AddToSpan(ctx)
185: 		}
186: 	}
187: 
188: 	return &emptypb.Empty{}, s.store.DeleteAuthentications(ctx, storageauth.Delete(storageauth.WithID(req.Id)))
189: }
190: 
191: // ExpireAuthenticationSelf expires the Authentication which was derived from the request context.
192: // If no expire_at is provided, the current time is used. This is useful for logging out a user.
193: // If the expire_at is greater than the current expiry time, the expiry time is extended.
194: func (s *Server) ExpireAuthenticationSelf(ctx context.Context, req *auth.ExpireAuthenticationSelfRequest) (*emptypb.Empty, error) {
195: 	if auth := authmiddlewaregrpc.GetAuthenticationFrom(ctx); auth != nil {
196: 		s.logger.Debug("ExpireAuthentication", zap.String("id", auth.Id))
197: 
198: 		if req.ExpiresAt == nil || !req.ExpiresAt.IsValid() {
199: 			req.ExpiresAt = flipt.Now()
200: 		}
201: 
202: 		return &emptypb.Empty{}, s.store.ExpireAuthenticationByID(ctx, auth.Id, req.ExpiresAt)
203: 	}
204: 
205: 	return nil, authmiddlewaregrpc.ErrUnauthenticated
206: }
