217: // ExportSpans completes one part of the implementation of a SpanExporter. Decodes span events to audit events.
218: func (s *SinkSpanExporter) ExportSpans(ctx context.Context, spans []sdktrace.ReadOnlySpan) error {
219: 	es := make([]Event, 0)
220: 
221: 	for _, span := range spans {
222: 		for _, e := range span.Events() {
223: 			e, err := decodeToEvent(e.Attributes)
224: 			if err != nil {
225: 				if !errors.Is(err, errEventNotValid) {
226: 					s.logger.Error("audit event not decodable", zap.Error(err))
227: 				}
228: 				continue
229: 			}
230: 			es = append(es, *e)
231: 		}
232: 	}
233: 
234: 	return s.SendAudits(ctx, es)
235: }
