237: // Shutdown will close all the registered sinks.
238: func (s *SinkSpanExporter) Shutdown(ctx context.Context) error {
239: 	var result error
240: 
241: 	for _, sink := range s.sinks {
242: 		err := sink.Close()
243: 		if err != nil {
244: 			result = multierror.Append(result, err)
245: 		}
246: 	}
247: 
248: 	return result
249: }
