251: // SendAudits wraps the methods of sending audits to various sinks.
252: func (s *SinkSpanExporter) SendAudits(ctx context.Context, es []Event) error {
253: 	if len(es) < 1 {
254: 		return nil
255: 	}
256: 
257: 	for _, sink := range s.sinks {
258: 		s.logger.Debug("performing batched sending of audit events", zap.Stringer("sink", sink), zap.Int("batch size", len(es)))
259: 		err := sink.SendAudits(ctx, es)
260: 		if err != nil {
261: 			s.logger.Debug("failed to send audits to sink", zap.Stringer("sink", sink))
262: 		}
263: 	}
264: 
265: 	return nil
266: }
