236: // ClientTokenAuthenticationInterceptor is a grpc.UnaryServerInterceptor which extracts a clientToken found
237: // within the authorization field on the incoming requests metadata.
238: // The fields value is expected to be in the form "Bearer <clientToken>".
239: func ClientTokenAuthenticationInterceptor(logger *zap.Logger, authenticator ClientTokenAuthenticator, o ...containers.Option[InterceptorOptions]) grpc.UnaryServerInterceptor {
240: 	var opts InterceptorOptions
241: 	containers.ApplyAll(&opts, o...)
242: 
243: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
244: 		// skip auth for any preconfigured servers
245: 		if skipped(ctx, info.Server, opts) {
246: 			logger.Debug("skipping authentication for server", zap.String("method", info.FullMethod))
247: 			return handler(ctx, req)
248: 		}
249: 
250: 		md, ok := metadata.FromIncomingContext(ctx)
251: 		if !ok {
252: 			logger.Error("unauthenticated", zap.String("reason", "metadata not found on context"))
253: 			return ctx, ErrUnauthenticated
254: 		}
255: 
256: 		clientToken, err := clientTokenFromMetadata(md)
257: 		if err != nil {
258: 			logger.Error("unauthenticated",
259: 				zap.String("reason", "no authorization provided"),
260: 				zap.Error(err))
261: 
262: 			return ctx, ErrUnauthenticated
263: 		}
264: 
265: 		auth, err := authenticator.GetAuthenticationByClientToken(ctx, clientToken)
266: 		if err != nil {
267: 			logger.Error("unauthenticated",
268: 				zap.String("reason", "error retrieving authentication for client token"),
269: 				zap.Error(err))
270: 
271: 			if errors.Is(err, context.Canceled) {
272: 				err = status.Error(codes.Canceled, err.Error())
273: 				return ctx, err
274: 			}
275: 
276: 			if errors.Is(err, context.DeadlineExceeded) {
277: 				err = status.Error(codes.DeadlineExceeded, err.Error())
278: 				return ctx, err
279: 			}
280: 
281: 			return ctx, ErrUnauthenticated
282: 		}
283: 
284: 		if auth.ExpiresAt != nil && auth.ExpiresAt.AsTime().Before(time.Now()) {
285: 			logger.Error("unauthenticated",
286: 				zap.String("reason", "authorization expired"),
287: 				zap.String("authentication_id", auth.Id),
288: 			)
289: 			return ctx, ErrUnauthenticated
290: 		}
291: 
292: 		return handler(ContextWithAuthentication(ctx, auth), req)
293: 	}
