342: func NamespaceMatchingInterceptor(logger *zap.Logger, o ...containers.Option[InterceptorOptions]) grpc.UnaryServerInterceptor {
343: 	var opts InterceptorOptions
344: 	containers.ApplyAll(&opts, o...)
345: 
346: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
347: 		// skip auth for any preconfigured servers
348: 		if skipped(ctx, info.Server, opts) {
349: 			logger.Debug("skipping authentication for server", zap.String("method", info.FullMethod))
350: 			return handler(ctx, req)
351: 		}
352: 
353: 		auth := GetAuthenticationFrom(ctx)
354: 		if auth == nil {
355: 			panic("authentication not found in context, middleware installed incorrectly")
356: 		}
357: 
358: 		// this mechanism only applies to static toke authentications
359: 		if auth.Method != authrpc.Method_METHOD_TOKEN {
360: 			return handler(ctx, req)
361: 		}
362: 
363: 		namespace, ok := auth.Metadata["io.flipt.auth.token.namespace"]
364: 		if !ok {
365: 			// if no namespace is provided then we should allow the request
366: 			return handler(ctx, req)
367: 		}
368: 
369: 		nsServer, ok := info.Server.(ScopedAuthenticationServer)
370: 		if !ok || !nsServer.AllowsNamespaceScopedAuthentication(ctx) {
371: 			logger.Error("unauthenticated",
372: 				zap.String("reason", "namespace is not allowed"))
373: 			return ctx, ErrUnauthenticated
374: 		}
375: 
376: 		namespace = strings.TrimSpace(namespace)
377: 		if namespace == "" {
378: 			return handler(ctx, req)
379: 		}
380: 
381: 		logger := logger.With(zap.String("expected_namespace", namespace))
382: 
383: 		var reqNamespace string
384: 		switch nsReq := req.(type) {
385: 		case flipt.Namespaced:
386: 			reqNamespace = nsReq.GetNamespaceKey()
387: 			if reqNamespace == "" {
388: 				reqNamespace = "default"
389: 			}
390: 		case flipt.BatchNamespaced:
391: 			// ensure that all namespaces referenced in
392: 			// the batch are the same
393: 			for _, ns := range nsReq.GetNamespaceKeys() {
394: 				if ns == "" {
395: 					ns = "default"
396: 				}
397: 
398: 				if reqNamespace == "" {
399: 					reqNamespace = ns
400: 					continue
401: 				}
402: 
403: 				if reqNamespace != ns {
404: 					logger.Error("unauthenticated",
405: 						zap.String("reason", "namespace is not allowed"))
406: 					return ctx, ErrUnauthenticated
407: 				}
408: 			}
409: 		default:
410: 			// if the the token has a namespace but the request does not then we should reject the request
411: 			logger.Error("unauthenticated",
412: 				zap.String("reason", "namespace is not allowed"))
413: 			return ctx, ErrUnauthenticated
414: 		}
415: 
416: 		if reqNamespace != namespace {
417: 			logger.Error("unauthenticated",
418: 				zap.String("reason", "namespace is not allowed"))
419: 			return ctx, ErrUnauthenticated
420: 		}
421: 
422: 		return handler(ctx, req)
423: 	}
424: }
