426: func clientTokenFromMetadata(md metadata.MD) (string, error) {
427: 	if authenticationHeader := md.Get(authenticationHeaderKey); len(authenticationHeader) > 0 {
428: 		return fromAuthorization(authenticationHeader[0], authenticationSchemeBearer)
429: 	}
430: 
431: 	cookie, err := cookieFromMetadata(md, middlewarecommon.TokenCookieKey)
432: 	if err != nil {
433: 		return "", err
434: 	}
435: 
436: 	return cookie.Value, nil
437: }
